  "vim.easymotion": true,
  "vim.hlsearch": true,
  "vim.incsearch": true,
  "vim.leader": "<Space>",
  "vim.scroll": 20,
  "vim.scrollSpeed": 1,
  "vim.smoothScrolling": true,
  "vim.useCtrlKeys": true,
  "vim.useSystemClipboard": true,
  "vim.handleKeys": {
    "<tab>": false,
    "<S-tab>": false,
    "<f10>": false,
    "<f11>": false,
    "<f5>": false,
    "<f9>": false
  },

  // Vim Insert Mode Bindings
  "vim.insertModeKeyBindings": [
    {
      "before": ["j", "j"],
      "after": ["<Esc>"]
    }
  ],

  // Vim Normal Mode Bindings (Non-Recursive)
  "vim.normalModeKeyBindingsNonRecursive": [
    // NAVIGATION
    {
      "before": ["<space>"],
      "commands": ["whichkey.show"]
    },
    // switch b/w buffers
    { "before": ["<S-h>"], "commands": [":bprevious"] },
    { "before": ["<S-l>"], "commands": [":bnext"] },

    // Tab navigation
    {
      "before": ["g", "<tab>"],
      "commands": ["workbench.action.quickOpenPreviousRecentlyUsedEditor"]
    },
    {
      "before": ["g", "t"],
      "commands": ["workbench.action.nextEditor"]
    },
    {
      "before": ["g", "T"],
      "commands": ["workbench.action.previousEditor"]
    },

    // splits
    { "before": ["leader", "v"], "commands": [":vsplit"] },
    { "before": ["leader", "s"], "commands": [":split"] },

    // panes
    {
      "before": ["leader", "h"],
      "commands": ["workbench.action.focusLeftGroup"]
    },
    {
      "before": ["leader", "j"],
      "commands": ["workbench.action.focusBelowGroup"]
    },
    {
      "before": ["leader", "k"],
      "commands": ["workbench.action.focusAboveGroup"]
    },
    {
      "before": ["leader", "l"],
      "commands": ["workbench.action.focusRightGroup"]
    },

    // FILE OPERATIONS
    { "before": ["leader", "w"], "commands": [":w!"] },
    { "before": ["leader", "q"], "commands": [":q!"] },
    { "before": ["leader", "x"], "commands": [":x!"] },
    { "before": ["leader", "f"], "commands": ["workbench.action.quickOpen"] },
    { "before": ["leader", "r"], "commands": ["workbench.action.gotoSymbol"] },
    { "before": ["leader", "p"], "commands": ["editor.action.formatDocument"] },

    // Quick text search
    {
      "before": ["leader", "g"],
      "commands": ["workbench.action.quickTextSearch"]
    },

    // Search Editor: New Search Editor
    {
      "before": ["leader", "o", "s"],
      "commands": ["search.action.openNewEditor"]
    },

    // Apply search editor changes
    {
      "before": ["leader", "w", "s"],
      "commands": ["searchEditorApplyChanges.apply"]
    },

    {
      "before": ["leader", "n", "e"],
      "commands": ["workbench.files.action.focusFilesExplorer"]
    },
    // DIAGNOSTICS & CODE ACTIONS
    {
      "before": ["[", "d"],
      "commands": ["editor.action.marker.prev"]
    },
    {
      "before": ["]", "d"],
      "commands": ["editor.action.marker.next"]
    },
    {
      "before": ["<leader>", "c", "a"],
      "commands": ["editor.action.quickFix"]
    },
    {
      "before": ["g", "h"],
      "commands": ["editor.action.showDefinitionPreviewHover"]
    },

