    {
      "before": ["<leader>", "d", "v"],
      "commands": ["workbench.debug.action.focusVariablesView"]
    },
    {
      "before": ["<leader>", "d", "w"],
      "commands": ["workbench.debug.action.focusWatchView"]
    },
    {
      "before": ["<leader>", "d", "k"],
      "commands": ["workbench.debug.action.focusCallStackView"]
    },
    {
      "before": ["<leader>", "d", "h"],
